const res = await fetch('https://wttr.in/?format=j1')
const data = await res.json()
const c = data.current_condition?.[0] || {}
const area = data.nearest_area?.[0] || {}
const weather = data.weather?.[0] || {}
return {
  area: area.areaName?.[0]?.value || area.areaName?.[0] || area.areaName || "Unknown location",
  region: area.region?.[0]?.value || area.region?.[0] || area.region || "",
  country: area.country?.[0]?.value || area.country?.[0] || area.country || "",
  tempC: c.temp_C,
  feelsLikeC: c.FeelsLikeC,
  humidity: c.humidity,
  description: c.weatherDesc?.[0]?.value || c.weatherDesc?.[0] || c.weatherDesc,
  windKph: c.windspeedKmph,
  precipitationMm: c.precipMM,
  forecastToday: {
    maxtempC: weather.maxtempC,
    mintempC: weather.mintempC,
    avgtempC: weather.avgtempC,
    hourly: weather.hourly?.map(h => ({
      time: h.time,
      tempC: h.tempC,
      chanceofrain: h.chanceofrain,
      weatherDesc: h.weatherDesc?.[0]?.value || h.weatherDesc?.[0] || h.weatherDesc
    }))
  }
}

