const spaces = await space.spaces.listSpaces()
const target = spaces.find(s => /game room/i.test(s.name || s.id || ""))
if (!target) return { error: "game room space not found", spaces }
const removed = await (space.spaces.deleteSpace ? space.spaces.deleteSpace(target.id) : (async () => {
  const fs = await space.api.fileList(target.id, true)
  return { deleted: false, files: fs }
})())
return { target, removed }

